INSERT INTO `journey_templates` VALUES ('adventure-safari','Desert Adventure & Safari Expedition','Experience Siwa\'s dramatic landscapes through 4x4 sand sea expeditions, camel trekking, and guided heritage walks. Discover ancient sites and natural wonders in authentic style.','Grand Sand Sea Exploration',3,'[\"safaris\"]','[\"adventure\", \"accommodation\", \"logistics\"]','https://images.unsplash.com/photo-1507525428034-b723cf961d3e?q=80&w=800','fa-compass','#10b981','[\"4x4 sand sea expedition\", \"Camel trek sunset\", \"Ancient site tours\", \"Stargazing night camp\", \"Heritage walking tour\"]',NULL,NULL,900,1600,'challenging','October to April',10,NULL,4,1,1,'2026-05-29 22:26:33','2026-05-29 22:26:33',0,NULL,NULL,0,0,NULL,NULL,NULL,NULL,NULL),('artisan-deep-dive','Artisan Crafts & Trades Experience','Work alongside master craftspeople to learn traditional Siwan embroidery, pottery, and rock salt lamp creation. Support local artisans while creating your own souvenirs.','Hands-On Heritage Craftsmanship',4,'[\"crafts\"]','[\"crafts\", \"accommodation\", \"food\"]','https://images.unsplash.com/photo-1513519245088-0e12902e5a38?q=80&w=800','fa-store','#ef4444','[\"Embroidery workshop\", \"Pottery studio visit\", \"Rock salt lamp creation\", \"Local artisan meeting\", \"Craft market tour\"]',NULL,NULL,600,1200,'moderate','Year-round',8,NULL,3,1,1,'2026-05-29 22:26:33','2026-05-29 22:26:33',0,NULL,NULL,0,0,NULL,NULL,NULL,NULL,NULL),('culinary-journey','Culinary & Slow Food Experience','Discover ancient Siwan gastronomy through hands-on cooking classes, farm visits to organic date orchards, and dining experiences with local chefs. Taste the authentic flavors of the desert.','Farm to Table Heritage',3,'[\"slow-food\"]','[\"food\", \"accommodation\", \"adventure\"]','https://images.unsplash.com/photo-1509316785289-025f5b846b35?q=80&w=800','fa-utensils','#f59e0b','[\"Olive oil pressing\", \"Date harvest tour\", \"Traditional cooking class\", \"Local market tour\", \"Farm-to-table dinner\"]',NULL,NULL,700,1400,'moderate','September to May',6,NULL,2,1,1,'2026-05-29 22:26:33','2026-05-29 22:26:33',0,NULL,NULL,0,0,NULL,NULL,NULL,NULL,NULL),('cultural-immersion','Cultural & Heritage Immersion','Deep dive into Siwan culture through local homestays, traditional ceremonies, museum visits, and conversations with community elders. Understand the soul of Siwa.','Living History & Community Connection',5,'[\"wellness\", \"slow-food\", \"crafts\"]','[\"accommodation\", \"food\", \"crafts\", \"adventure\"]','https://images.unsplash.com/photo-1516026672322-5e36f05c2ce7?q=80&w=800','fa-book','#a78bfa','[\"Homestay experience\", \"Local ceremony participation\", \"Museum tour\", \"Elder storytelling\", \"Traditional music session\"]',NULL,NULL,650,1300,'moderate','October to May',6,NULL,5,1,1,'2026-05-29 22:26:33','2026-05-29 22:26:33',0,NULL,NULL,0,0,NULL,NULL,NULL,NULL,NULL),('real-estate-investment-tour','Real Estate Investment Tour','Explore premium land and property opportunities in Siwa. This curated journey combines luxury desert experience with exclusive viewings of development projects, agricultural land, and residential properties. Meet with local developers, understand zoning regulations, and discover the investment potential of this emerging market.','Land & Property Development Exploration',5,'[\"investment\",\"real-estate\",\"business\"]','[\"accommodation\",\"food\",\"transportation\",\"business-meetings\"]','https://images.unsplash.com/photo-1486406146926-c627a92ad1ab?q=80&w=800','fa-building','#3b82f6','[\"Developer briefings\",\"Land viewing tours\",\"Legal & compliance workshop\",\"Property valuation insights\",\"Networking dinner with investors\"]','[]','[]',3500,6500,'moderate','October to May',12,'Premium investment journey - include site visits to major projects',6,1,1,'2026-05-29 23:03:05','2026-05-29 23:03:05',1,'[\"real_estate\",\"agriculture\",\"business\"]','Discover high-potential real estate and agricultural land opportunities in Siwa\'s growing economy. From residential plots to commercial development zones to organic farming estates, see firsthand why investors are turning to this emerging desert market.',50000,15,'Siwa Development Consortium','invest@siwaconsortium.com | +20 100 123 4567','[{\"name\":\"Oasis Ridge Residential Complex\",\"location\":\"North Siwa Development Zone\",\"price_range\":\"$80K - $300K per unit\",\"description\":\"Luxury residential development with modern amenities\"},{\"name\":\"Agricultural Heritage Farms\",\"location\":\"South Siwa Oasis\",\"price_range\":\"$50K - $150K per hectare\",\"description\":\"Organic date palm and olive cultivation opportunities\"}]','[{\"investor\":\"Ahmed Hassan\",\"country\":\"Egypt\",\"investment\":\"$120K in residential plot\",\"year\":2021,\"result\":\"Property appreciated 35% in 3 years, now valued at $162K\"},{\"investor\":\"European Consortium\",\"country\":\"Germany\",\"investment\":\"$500K in agricultural land\",\"year\":2020,\"result\":\"Successfully growing organic dates, 18% annual ROI\"}]','Minimum investment $50K USD. Accredited investor status preferred. Passport required for all viewings. 48-hour notice for property site visits.'),('timeshare-vacation-opportunity','Timeshare & Vacation Ownership Experience','Explore the luxury timeshare and vacation property ownership model in Siwa. Experience premium resort amenities, meet with fractional ownership specialists, and learn how to secure guaranteed vacation time while building equity. This journey combines relaxation with financial planning.','Luxury Vacation Ownership & Resort Investment',4,'[\"investment\",\"luxury\",\"wellness\"]','[\"luxury-accommodation\",\"fine-dining\",\"resort-amenities\"]','https://images.unsplash.com/photo-1551632786-de41ec16a21d?q=80&w=800','fa-calendar-check','#ec4899','[\"5-star resort tour\",\"Timeshare presentation\",\"Financial advisor consultation\",\"Sunset spa treatment\",\"Exclusive investment cocktail\"]','[]','[]',2000,4000,'easy','Year-round',20,'Popular with families and couples - relaxation + investment',7,1,1,'2026-05-29 23:03:05','2026-05-29 23:03:05',1,'[\"timeshare\",\"vacation_ownership\",\"hospitality\"]','Own premium vacation weeks at world-class desert resorts without the burden of full property ownership. Choose your preferred dates, lock in pricing, and enjoy guaranteed access to luxury accommodations. Vacation ownership provides both lifestyle benefits and investment appreciation.',15000,8,'Siwa Resorts International','timeshare@siwaresorts.com | +20 100 988 7654','[{\"name\":\"Oasis Palace Resort - Desert Oasis Wing\",\"location\":\"Central Siwa\",\"price_range\":\"$15K - $45K per timeshare\",\"description\":\"Beachfront luxury with 2-3 week annual ownership options\"},{\"name\":\"Siwa Heritage Villas - Elite Membership\",\"location\":\"Oasis Valley\",\"price_range\":\"$20K - $60K per fractional share\",\"description\":\"Exclusive villas with chef, spa, and concierge services\"}]','[{\"investor\":\"Maria Santos\",\"country\":\"Portugal\",\"investment\":\"$25K timeshare at Oasis Palace\",\"year\":2019,\"result\":\"Vacationed annually for 5 years, property now worth $32K - 28% appreciation\"},{\"investor\":\"UK Family Trust\",\"country\":\"United Kingdom\",\"investment\":\"$40K for 2-week annual access\",\"year\":2022,\"result\":\"Rents out 1 week annually to cover costs, family uses remaining weeks\"}]','Minimum 18 years old. Credit check required. Valid passport for international investors. Flexibility required to maintain vacation schedule. 10% annual maintenance fees apply.'),('wellness-retreat','Wellness & Healing Retreat','Float in natural salt lakes, immerse yourself in therapeutic hot springs, and experience ancient sand bath treatments. This rejuvenating journey combines modern wellness practices with Siwa\'s natural healing resources.','Therapeutic Desert Sanctuary',4,'[\"wellness\"]','[\"wellness\", \"accommodation\", \"food\"]','https://images.unsplash.com/photo-1540555700478-4be289fbecef?q=80&w=800','fa-spa','#10B981','[\"Salt lake float\", \"Thermal spring immersion\", \"Sand bath therapy\", \"Yoga sunrise session\", \"Organic wellness meals\"]',NULL,NULL,800,1500,'easy','October to April',8,NULL,1,1,1,'2026-05-29 22:26:33','2026-05-29 23:00:20',0,'[]',NULL,0,0,NULL,NULL,NULL,NULL,NULL);
